def bssn_rhs_fused_fp64(F, dx, dy, dz, eta, lmbda, lambda_f, BSSN_CAHD_C, dt, h_ssl, sig_ssl, t):
    """fp64 fused BSSN RHS: fields in (dict, full padded shape), {field: d/dt} out.

    Signature-compatible with bssn_rhs_fused; fp64-locked, output-fanout trunk
    schedule. Derivatives computed inside the kernel (no derivative_bundle)."""
    shape = F['alpha'].shape
    feat = jnp.stack([F[n] for n in FIELD_INPUTS]).astype(PDTYPE)
    scal = jnp.asarray([eta, BSSN_CAHD_C, dt, h_ssl, sig_ssl, t, dx, dy, dz,
                        lmbda[0], lmbda[1], lmbda[2], lmbda[3],
                        lambda_f[0], lambda_f[1]], dtype=PDTYPE)
    out = pl.pallas_call(
        _kernel,
        grid=(1,),
        in_specs=[pl.BlockSpec((NF,) + shape, lambda i: (0,) + (0,) * len(shape)),
                  pl.BlockSpec((NSCAL,), lambda i: (0,))],
        out_specs=pl.BlockSpec((NOUT,) + shape, lambda i: (0,) + (0,) * len(shape)),
        out_shape=jax.ShapeDtypeStruct((NOUT,) + shape, PDTYPE),
        interpret=_INTERPRET,
    )(feat, scal)
    return {field: out[i].astype(jnp.float64)
            for i, field in enumerate(OUTPUT_FIELDS)}
